public int eliminateMaximum(int[] dist, int[] speed) {
    int n = dist.length;
    int[] timeToReachCity = new int[n];
    for (int i = 0; i < n; i++) {
        timeToReachCity[i] = (dist[i] + speed[i] - 1) / speed[i];
    }
    Arrays.sort(timeToReachCity);
    int eliminated = 0;
    for (int i = 0; i < n && timeToReachCity[i] > i; i++) {
        eliminated++;
    }
    return eliminated;
}
```

